package cmd

import (
	"encoding/json"
	"fmt"
	"io"
	"sort"
	"time"

	"github.com/DocumentDrivenDX/ddx/internal/agent"
	"github.com/DocumentDrivenDX/ddx/internal/workerstatus"
	"github.com/spf13/cobra"
)

// newWorkStatusCommand creates the "ddx work status" subcommand: a
// project-scoped live-worker report.
//
// The default report lists only live `ddx work` / `ddx try` processes whose
// resolved project root matches the requested project. The earlier failure
// mode this command exists to prevent is a global `ps | grep ddx work` scan
// surfacing a worker from another repository while operators are asking
// about a specific project's queue.
func (f *CommandFactory) newWorkStatusCommand() *cobra.Command {
	cmd := &cobra.Command{
		Use:   "status",
		Short: "Show live ddx workers scoped to this project",
		Long: `status lists the live ddx worker processes (ddx work / ddx try)
whose project root matches the current project. The default scope is the
git root of the working directory; pass --project to override or
--all-projects to inspect every worker on the host.

Workers from other repositories are intentionally excluded from the
default view. Reporting them as evidence that "the worker is still
running" hides whether the requested project's queue has stalled.

Output columns (terminal):
  PID         — process id of the worker
  AGE         — wall-clock age since the worker process started
  COMMAND     — the worker's command line (truncated for terminals)
  BEAD        — active bead id when it can be inferred from argv or the
                isolated execute-bead worktree
  ATTEMPT     — active attempt id when a fresh worker liveness sidecar
                records one for the live worker
  WORKTREE    — execute-bead worktree path when the worker is inside one

JSON output preserves the full set of fields including project_root,
attempt_id, phase, child_pid, and last_activity_at when available.`,
		Example: `  # Show live workers for the current project
  ddx work status

  # JSON for piping to jq
  ddx work status --json

  # Explicit cross-project view
  ddx work status --all-projects --json`,
		Args: cobra.NoArgs,
		RunE: f.runWorkStatus,
	}
	cmd.Flags().String("project", "", "Target project root path (default: CWD git root). Env: DDX_PROJECT_ROOT")
	cmd.Flags().Bool("all-projects", false, "Report workers from every project; opt-in escape hatch")
	cmd.Flags().Bool("json", false, "Output as JSON")
	return cmd
}

// workerStatusScanner is set by tests via the CommandFactory to inject a
// deterministic worker set without spawning real processes.
type workerStatusScanner = workerstatus.Scanner

// WorkStatusReport is the JSON payload emitted by `ddx work status --json`.
type WorkStatusReport struct {
	ProjectRoot string                    `json:"project_root,omitempty"`
	Scope       string                    `json:"scope"`
	Workers     []workerstatus.LiveWorker `json:"workers"`
}

func (f *CommandFactory) runWorkStatus(cmd *cobra.Command, _ []string) error {
	projectFlag, _ := cmd.Flags().GetString("project")
	allProjects, _ := cmd.Flags().GetBool("all-projects")
	asJSON, _ := cmd.Flags().GetBool("json")

	projectRoot := resolveProjectRoot(projectFlag, f.WorkingDir)

	scanner := f.workerScanner()
	all, err := scanner.Scan(cmd.Context())
	if err != nil {
		return fmt.Errorf("scan live workers: %w", err)
	}

	now := time.Now().UTC()
	report := WorkStatusReport{
		ProjectRoot: projectRoot,
		Scope:       "project",
		Workers: enrichWorkersWithRunState(
			workerstatus.EnrichWithFreshLiveness(filterAndSortWorkers(all, projectRoot, allProjects), now),
			now,
		),
	}
	if allProjects {
		report.Scope = "all-projects"
	}

	out := cmd.OutOrStdout()
	if asJSON {
		return writeWorkStatusJSON(out, report)
	}
	writeWorkStatusText(out, report)
	return nil
}

func (f *CommandFactory) workerScanner() workerStatusScanner {
	if f.workerScannerOverride != nil {
		return f.workerScannerOverride
	}
	return workerstatus.New()
}

// enrichWorkersWithRunState fills bead/attempt/worktree from a fresh
// per-attempt run-state record (.ddx/run-state/<attempt>.json) whose PID
// matches a live worker, when liveness enrichment did not supply them — e.g.
// the liveness sidecar was absent, start-time-skewed, or its attempt id was
// stale (ddx-f9b41107). Run-state is read from each worker's own project root,
// so all-projects scope does not leak attempts across projects.
func enrichWorkersWithRunState(workers []workerstatus.LiveWorker, now time.Time) []workerstatus.LiveWorker {
	byProject := make(map[string][]agent.RunState)
	for i := range workers {
		w := &workers[i]
		if w.PID <= 0 || (w.BeadID != "" && w.AttemptID != "" && w.ExecutionWorktree != "") {
			continue
		}
		states, ok := byProject[w.ProjectRoot]
		if !ok {
			states, _ = agent.ReadRunStates(w.ProjectRoot)
			byProject[w.ProjectRoot] = states
		}
		rec, ok := freshestRunStateForPID(states, w.PID, now)
		if !ok {
			continue
		}
		if w.BeadID == "" {
			w.BeadID = rec.BeadID
		}
		if w.AttemptID == "" {
			w.AttemptID = rec.AttemptID
		}
		if w.ExecutionWorktree == "" {
			w.ExecutionWorktree = rec.WorktreePath
		}
	}
	return workers
}

// freshestRunStateForPID returns the most recently refreshed non-expired
// run-state record for pid, if any.
func freshestRunStateForPID(states []agent.RunState, pid int, now time.Time) (agent.RunState, bool) {
	var best agent.RunState
	found := false
	for _, s := range states {
		if s.PID != pid {
			continue
		}
		if !s.ExpiresAt.IsZero() && now.After(s.ExpiresAt) {
			continue
		}
		if !found || s.RefreshedAt.After(best.RefreshedAt) {
			best = s
			found = true
		}
	}
	return best, found
}

func filterAndSortWorkers(all []workerstatus.LiveWorker, projectRoot string, allProjects bool) []workerstatus.LiveWorker {
	var filtered []workerstatus.LiveWorker
	if allProjects {
		filtered = append(filtered, all...)
	} else {
		filtered = workerstatus.FilterByProject(all, projectRoot)
	}
	sort.SliceStable(filtered, func(i, j int) bool {
		if filtered[i].StartedAt.Equal(filtered[j].StartedAt) {
			return filtered[i].PID < filtered[j].PID
		}
		return filtered[i].StartedAt.Before(filtered[j].StartedAt)
	})
	return filtered
}

func writeWorkStatusJSON(out io.Writer, report WorkStatusReport) error {
	if report.Workers == nil {
		report.Workers = []workerstatus.LiveWorker{}
	}
	enc := json.NewEncoder(out)
	enc.SetIndent("", "  ")
	return enc.Encode(report)
}

func writeWorkStatusText(out io.Writer, report WorkStatusReport) {
	if len(report.Workers) == 0 {
		if report.Scope == "all-projects" {
			fmt.Fprintln(out, "No live ddx workers found on this host.")
			return
		}
		fmt.Fprintf(out, "No live ddx workers for project %s.\n", report.ProjectRoot)
		return
	}
	if report.Scope == "all-projects" {
		fmt.Fprintf(out, "live ddx workers (all projects): %d\n", len(report.Workers))
	} else {
		fmt.Fprintf(out, "live ddx workers for %s: %d\n", report.ProjectRoot, len(report.Workers))
	}
	for _, w := range report.Workers {
		bead := w.BeadID
		if bead == "" {
			bead = "-"
		}
		attempt := w.AttemptID
		if attempt == "" {
			attempt = "-"
		}
		worktree := w.ExecutionWorktree
		if worktree == "" {
			worktree = "-"
		}
		line := fmt.Sprintf("  pid=%d age=%s project=%s bead=%s attempt=%s worktree=%s",
			w.PID, w.Age, w.ProjectRoot, bead, attempt, worktree)
		if w.Phase != "" {
			line += fmt.Sprintf(" phase=%s", w.Phase)
		}
		if w.Message != "" {
			line += fmt.Sprintf(" message=%q", w.Message)
		}
		fmt.Fprintf(out, "%s\n    %s\n", line, w.Command)
	}
}

package cmd

import (
	"context"
	"encoding/json"
	"fmt"
	"strings"
	"time"

	"github.com/DocumentDrivenDX/ddx/internal/bead"
	"github.com/DocumentDrivenDX/ddx/internal/ddxroot"
	"github.com/DocumentDrivenDX/ddx/internal/workerstatus"
	"github.com/spf13/cobra"
)

// WorkFocusActiveWorker is one entry in the active_workers section.
type WorkFocusActiveWorker struct {
	WorkerID       string `json:"worker_id"`
	CurrentBead    string `json:"current_bead,omitempty"`
	AttemptID      string `json:"attempt_id,omitempty"`
	Phase          string `json:"phase,omitempty"`
	LastActivityAt string `json:"last_activity_at,omitempty"`
}

// WorkFocusBead is one item in the operator-attention section.
type WorkFocusBead struct {
	ID              string `json:"id"`
	Title           string `json:"title"`
	Reason          string `json:"reason,omitempty"`
	SuggestedAction string `json:"suggested_action,omitempty"`
}

// WorkFocusBlockedBead is one item in the blocked_or_planning section.
type WorkFocusBlockedBead struct {
	ID          string `json:"id"`
	Title       string `json:"title"`
	BlockerKind string `json:"blocker_kind"`
	Detail      string `json:"detail,omitempty"`
}

// WorkFocusReadySummary is the ready-queue depth summary.
type WorkFocusReadySummary struct {
	Count int    `json:"count"`
	Depth string `json:"depth"` // "empty", "shallow", "moderate", "deep"
}

// WorkFocusReport is the structured result of "ddx work focus".
type WorkFocusReport struct {
	HumanRequired        []WorkFocusBead         `json:"human_required"`
	BlockedOrPlanning    []WorkFocusBlockedBead  `json:"blocked_or_planning"`
	ReadySummary         WorkFocusReadySummary   `json:"ready_summary"`
	ActiveWorkers        []WorkFocusActiveWorker `json:"active_workers,omitempty"`
	WorkerRecommendation string                  `json:"worker_recommendation"`
	Unknowns             []string                `json:"unknowns"`
}

// workerReadyDepthLabel returns a human-readable depth label for the ready count.
func workerReadyDepthLabel(count int) string {
	switch {
	case count == 0:
		return "empty"
	case count <= 1:
		return "shallow"
	case count <= 3:
		return "moderate"
	default:
		return "deep"
	}
}

// buildWorkFocusReport queries the store and returns a WorkFocusReport.
//
// projectRoot, when non-empty, enables the active_workers section: any
// .ddx/workers/<id>/status.json sidecar with a last_activity_at within
// workerstatus.LivenessTTL is reported as a live worker. This lets the
// operator-facing view treat a long-running attempt as active even when the
// bead tracker's claim timestamp has not changed (heartbeats are written
// outside beads.jsonl to avoid tracker churn).
func buildWorkFocusReport(store *bead.Store, projectRoot string) (WorkFocusReport, error) {
	// Collect operator-attention beads (status=proposed, any dep state).
	operatorAttentionBeads, err := store.ProposedOperatorAttention()
	if err != nil {
		return WorkFocusReport{}, fmt.Errorf("work focus: operator attention query: %w", err)
	}

	// Build a set of operator-attention IDs so we can exclude them from blocked section.
	operatorAttentionSet := make(map[string]bool, len(operatorAttentionBeads))
	humanRequired := make([]WorkFocusBead, 0, len(operatorAttentionBeads))
	for _, b := range operatorAttentionBeads {
		operatorAttentionSet[b.ID] = true
		meta := bead.GetNeedsHumanMeta(b)
		item := WorkFocusBead{
			ID:    b.ID,
			Title: b.Title,
		}
		if meta.Reason != "" {
			item.Reason = meta.Reason
		} else if meta.Summary != "" {
			item.Reason = meta.Summary
		}
		if meta.SuggestedAction != "" {
			item.SuggestedAction = meta.SuggestedAction
		}
		humanRequired = append(humanRequired, item)
	}

	// Collect all blocked beads; exclude operator-attention beads already captured above.
	allBlocked, err := store.BlockedAll()
	if err != nil {
		return WorkFocusReport{}, fmt.Errorf("work focus: blocked query: %w", err)
	}
	var blockedOrPlanning []WorkFocusBlockedBead
	for _, bb := range allBlocked {
		if operatorAttentionSet[bb.ID] {
			continue
		}
		item := WorkFocusBlockedBead{
			ID:          bb.ID,
			Title:       bb.Title,
			BlockerKind: bb.Blocker.Kind,
		}
		switch bb.Blocker.Kind {
		case bead.BlockerKindDependency:
			if len(bb.Blocker.UnclosedDepIDs) > 0 {
				item.Detail = "unclosed deps: " + strings.Join(bb.Blocker.UnclosedDepIDs, ", ")
			}
		case bead.BlockerKindRetryCooldown:
			if bb.Blocker.NextEligibleAt != "" {
				item.Detail = "retry after: " + bb.Blocker.NextEligibleAt
			}
		default:
			if bb.Blocker.Reason != "" {
				item.Detail = bb.Blocker.Reason
			}
		}
		blockedOrPlanning = append(blockedOrPlanning, item)
	}

	// Collect worker-ready depth.
	readyBeads, err := store.ReadyExecution()
	if err != nil {
		return WorkFocusReport{}, fmt.Errorf("work focus: ready query: %w", err)
	}
	readyCount := len(readyBeads)
	readySummary := WorkFocusReadySummary{
		Count: readyCount,
		Depth: workerReadyDepthLabel(readyCount),
	}

	// Observe in_progress beads as a capacity signal.
	inProgressBeads, err := store.List(bead.StatusInProgress, "", nil)
	if err != nil {
		return WorkFocusReport{}, fmt.Errorf("work focus: in_progress query: %w", err)
	}
	inProgressCount := len(inProgressBeads)

	// Active worker sidecars: workers whose status.json was updated within
	// workerstatus.LivenessTTL are treated as active even when the bead
	// tracker claim timestamp is older. This is the operator-facing answer
	// to "is the worker alive?" — the bead row alone cannot answer it
	// because heartbeats are recorded outside beads.jsonl.
	activeWorkers := collectActiveWorkers(projectRoot, time.Now())

	// Conservative worker recommendation. Treat each active sidecar as
	// observed capacity in addition to in_progress beads.
	workerRec := buildWorkerRecommendation(readyCount, inProgressCount+len(activeWorkers))

	// Unknowns: worker process liveness is not verifiable from the bead store.
	var unknowns []string
	if inProgressCount > 0 && len(activeWorkers) == 0 {
		unknowns = append(unknowns, fmt.Sprintf(
			"worker process liveness: %d bead(s) are in_progress but no active worker sidecar is fresh; check `ddx work status` for live processes",
			inProgressCount,
		))
	}

	return WorkFocusReport{
		HumanRequired:        humanRequired,
		BlockedOrPlanning:    blockedOrPlanning,
		ReadySummary:         readySummary,
		ActiveWorkers:        activeWorkers,
		WorkerRecommendation: workerRec,
		Unknowns:             unknowns,
	}, nil
}

// collectActiveWorkers reads .ddx/workers/*/status.json sidecars under
// projectRoot and returns the ones whose last_activity_at is within
// workerstatus.LivenessTTL. Empty projectRoot or a missing workers dir
// yields nil.
func collectActiveWorkers(projectRoot string, now time.Time) []WorkFocusActiveWorker {
	if projectRoot == "" {
		return nil
	}
	records, err := workerstatus.ListLiveness(projectRoot)
	if err != nil {
		return nil
	}
	var out []WorkFocusActiveWorker
	for _, rec := range records {
		if !rec.IsFresh(now) {
			continue
		}
		out = append(out, WorkFocusActiveWorker{
			WorkerID:       rec.WorkerID,
			CurrentBead:    rec.CurrentBead,
			AttemptID:      rec.AttemptID,
			Phase:          rec.Phase,
			LastActivityAt: rec.LastActivityAt.UTC().Format(time.RFC3339Nano),
		})
	}
	return out
}

// buildWorkerRecommendation returns a conservative recommendation string.
// It suggests another worker only when ready depth is high and capacity is observable.
func buildWorkerRecommendation(readyCount, inProgressCount int) string {
	switch {
	case readyCount == 0:
		return "Queue is empty; no worker action needed."
	case inProgressCount > 0 && readyCount > 0:
		return fmt.Sprintf(
			"%d bead(s) ready; %d bead(s) currently claimed (in_progress). Monitor progress or run 'ddx work' to add capacity.",
			readyCount, inProgressCount,
		)
	case readyCount >= 3:
		return fmt.Sprintf(
			"%d bead(s) ready and no active workers detected; consider running: ddx work",
			readyCount,
		)
	default:
		return fmt.Sprintf(
			"%d bead(s) ready; run 'ddx work' to process.",
			readyCount,
		)
	}
}

func (f *CommandFactory) newWorkFocusCommand() *cobra.Command {
	cmd := &cobra.Command{
		Use:   "focus",
		Short: "Show work requiring operator attention",
		Long: `focus shows a read-only summary of queue items that require operator
attention — proposed beads, external blockers, dependency-waiting or
planning-required beads — along with a conservative worker-capacity
recommendation based on observable queue depth and in-progress signals.

Unlike 'ddx work plan', focus is designed for interactive queue stewardship:
it surfaces the items workers will NOT pick up and recommends operator actions.
Worker-ready beads are not listed as primary intervention items; they appear
only as a depth summary.

Use --json for machine-readable output with stable keys:
  human_required, blocked_or_planning, ready_summary,
  worker_recommendation, unknowns
`,
		Example: `  # Show intervention queue in human-readable format
  ddx work focus

  # Machine-readable output
  ddx work focus --json | jq '.human_required'`,
		Args: cobra.NoArgs,
		RunE: f.runWorkFocus,
	}
	cmd.Flags().Bool("json", false, "Output as JSON object with stable keys")
	return cmd
}

func (f *CommandFactory) runWorkFocus(cmd *cobra.Command, _ []string) error {
	asJSON, _ := cmd.Flags().GetBool("json")

	ddxDir := ddxroot.Path(context.Background(), f.WorkingDir)
	store := bead.NewStore(ddxDir)

	report, err := buildWorkFocusReport(store, f.WorkingDir)
	if err != nil {
		return err
	}

	if asJSON {
		enc := json.NewEncoder(cmd.OutOrStdout())
		enc.SetIndent("", "  ")
		return enc.Encode(report)
	}
	return printWorkFocusText(cmd, report)
}

func printWorkFocusText(cmd *cobra.Command, r WorkFocusReport) error {
	out := cmd.OutOrStdout()

	// Section: Operator attention
	fmt.Fprintf(out, "=== Operator attention (%d) ===\n", len(r.HumanRequired))
	if len(r.HumanRequired) == 0 {
		fmt.Fprintln(out, "  (none)")
	} else {
		for _, item := range r.HumanRequired {
			fmt.Fprintf(out, "  [%s] %s\n", item.ID, item.Title)
			if item.Reason != "" {
				fmt.Fprintf(out, "       reason: %s\n", item.Reason)
			}
			if item.SuggestedAction != "" {
				fmt.Fprintf(out, "       suggested action: %s\n", item.SuggestedAction)
			}
		}
	}

	// Section: Blocked / planning
	fmt.Fprintf(out, "\n=== Blocked / planning (%d) ===\n", len(r.BlockedOrPlanning))
	if len(r.BlockedOrPlanning) == 0 {
		fmt.Fprintln(out, "  (none)")
	} else {
		for _, item := range r.BlockedOrPlanning {
			fmt.Fprintf(out, "  [%s] %s\n", item.ID, item.Title)
			if item.Detail != "" {
				fmt.Fprintf(out, "       blocker: %s — %s\n", item.BlockerKind, item.Detail)
			} else {
				fmt.Fprintf(out, "       blocker: %s\n", item.BlockerKind)
			}
		}
	}

	// Section: Worker-ready summary
	fmt.Fprintf(out, "\n=== Worker-ready summary ===\n")
	fmt.Fprintf(out, "  %d bead(s) ready for worker execution (%s)\n", r.ReadySummary.Count, r.ReadySummary.Depth)

	// Section: Active workers (sidecar-derived). Surfaced so an operator
	// asking "is the worker alive?" gets a positive answer even when the
	// bead tracker's claim timestamp has not advanced.
	if len(r.ActiveWorkers) > 0 {
		fmt.Fprintf(out, "\n=== Active workers (%d) ===\n", len(r.ActiveWorkers))
		for _, w := range r.ActiveWorkers {
			fmt.Fprintf(out, "  [%s] bead=%s attempt=%s phase=%s last=%s\n",
				w.WorkerID, dashIfEmpty(w.CurrentBead), dashIfEmpty(w.AttemptID),
				dashIfEmpty(w.Phase), w.LastActivityAt)
		}
	}

	// Section: Worker recommendation
	fmt.Fprintf(out, "\n=== Worker recommendation ===\n")
	fmt.Fprintf(out, "  %s\n", r.WorkerRecommendation)

	// Section: Unknowns
	fmt.Fprintf(out, "\n=== Unknowns ===\n")
	if len(r.Unknowns) == 0 {
		fmt.Fprintln(out, "  (none)")
	} else {
		for _, u := range r.Unknowns {
			fmt.Fprintf(out, "  - %s\n", u)
		}
	}

	return nil
}

func dashIfEmpty(s string) string {
	if s == "" {
		return "-"
	}
	return s
}
